const f={1:1e3,2:200,3:300,4:400,5:500,6:600};function h(i){const n=new Set,c=[],a=[1,2,3,4,5],d=[];for(const e of a){const s=i.findIndex((o,t)=>o===e&&!n.has(t));s!==-1&&d.push(s)}d.length===5&&(d.forEach(e=>n.add(e)),c.push({type:"straight",diceIndices:d,points:1500}));for(let e=1;e<=6;e++){let o=i.map((t,r)=>t===e&&!n.has(r)?r:-1).filter(t=>t!==-1);for(;o.length>=3;){const t=o.slice(0,3);t.forEach(r=>n.add(r)),c.push({type:"triple",face:e,diceIndices:t,points:f[e]}),o=o.slice(3)}}return i.forEach((e,s)=>{n.has(s)||(e===1&&(n.add(s),c.push({type:"single",face:1,diceIndices:[s],points:100})),e===5&&(n.add(s),c.push({type:"single",face:5,diceIndices:[s],points:50})))}),c}function p(i){return i.reduce((n,c)=>n+c.points,0)}function l(i){return h(i).length===0}export{h as d,l as i,p as s};
